import React from 'react';
import styleMain from './Main.module.css';
import {Route} from "react-router-dom";
const Main = () =>  {
    return ( 
        <main className={styleMain.main}>
            <div>
                <Route component="Main" />
                <Route />
            </div>
        </main>
    );
}
 
export default Main;
